/**
 * client-side pagination using posts.json
 * loads latest posts generated by jekyll
 */

const POSTS_PER_PAGE = 5; // number of posts per page
let currentPage = 1;      // track selected page

document.addEventListener("DOMContentLoaded", () => {
  loadPosts();
});

/**
 * fetch posts.json with cache-busting
 */
function loadPosts() {
  fetch(`/posts.json?v=${Date.now()}`)
    .then(res => res.json())
    .then(posts => {
      if (!Array.isArray(posts) || posts.length === 0) {
        console.warn("no posts found in posts.json");
        return;
      }

      renderPagination(posts);
      renderPosts(posts, 1);
    })
    .catch(err => console.error("posts.json error:", err));
}

/**
 * render posts for selected page
 */
function renderPosts(posts, page) {
  const container = document.querySelector('.post-list');
  if (!container) return;

  container.innerHTML = "";

  const start = (page - 1) * POSTS_PER_PAGE;
  const selected = posts.slice(start, start + POSTS_PER_PAGE);

  selected.forEach(p => {
    const postEl = document.createElement("article");
    postEl.className = "post";

    postEl.innerHTML = `
      <h2><a href="${p.url}">${p.title}</a></h2>
      <time>${p.date}</time>
    `;

    container.appendChild(postEl);
  });

  updateActivePage(page);
  currentPage = page;
}

/**
 * create pagination buttons
 */
function renderPagination(posts) {
  const totalPages = Math.ceil(posts.length / POSTS_PER_PAGE);
  const box = document.querySelector('.pagination');
  if (!box) return;

  box.innerHTML = "";

  for (let i = 1; i <= totalPages; i++) {
    const btn = document.createElement("button");
    btn.textContent = i;
    btn.dataset.page = i;

    btn.addEventListener("click", () => {
      renderPosts(posts, i);
      scrollToTop();
    });

    box.appendChild(btn);
  }
}

/**
 * update active page button
 */
function updateActivePage(page) {
  const buttons = document.querySelectorAll(".pagination button");
  buttons.forEach(btn => {
    btn.classList.toggle("active", Number(btn.dataset.page) === page);
  });
}

/**
 * smooth scroll to page top
 */
function scrollToTop() {
  window.scrollTo({ top: 0, behavior: "smooth" });
}